record.field:
{
  "prompt": {
    "type": "string",
    "description": "Prompt for image generation",
    "required": true
  },
  "output_quality": {
    "type": "integer",
    "title": "Output Quality",
    "default": 95,
    "maximum": 100,
    "minimum": 0,
    "x-order": 4,
    "description": "Quality of the output images, from 0 to 100. 100 is best quality, 0 is lowest quality."
  },
  "return_temp_files": {
    "type": "boolean",
    "title": "Return Temp Files",
    "default": false,
    "x-order": 2,
    "description": "Return any temporary files, such as preprocessed controlnet images. Useful for debugging."
  },
  "randomise_seeds": {
    "type": "boolean",
    "title": "Randomise Seeds",
    "default": true,
    "x-order": 5,
    "description": "Automatically randomise seeds (seed, noise_seed, rand_seed)"
  },
  "force_reset_cache": {
    "type": "boolean",
    "title": "Force Reset Cache",
    "default": false,
    "x-order": 6,
    "description": "Force reset the ComfyUI cache before running the workflow. Useful for debugging."
  },
  "output_format": {
    "allOf": [
      {
        "enum": [
          "webp",
          "jpg",
          "png"
        ],
        "type": "string",
        "title": "output_format",
        "description": "An enumeration."
      }
    ],
    "default": "webp",
    "x-order": 3,
    "description": "Format of the output images"
  }
}

{
  "output_format": "{{output_format}}",
  "workflow_json": "{
  "3": {
    "inputs": {
      "seed": 156680208700286,
      "steps": 10,
      "cfg": 2.5,
      "sampler_name": "dpmpp_2m_sde",
      "scheduler": "karras",
      "denoise": 1,
      "model": [
        "4",
        0
      ],
      "positive": [
        "6",
        0
      ],
      "negative": [
        "7",
        0
      ],
      "latent_image": [
        "5",
        0
      ]
    },
    "class_type": "KSampler",
    "_meta": {
      "title": "KSampler"
    }
  },
  "4": {
    "inputs": {
      "ckpt_name": "SDXL-Flash.safetensors"
    },
    "class_type": "CheckpointLoaderSimple",
    "_meta": {
      "title": "Load Checkpoint"
    }
  },
  "5": {
    "inputs": {
      "width": 1024,
      "height": 1024,
      "batch_size": 1
    },
    "class_type": "EmptyLatentImage",
    "_meta": {
      "title": "Empty Latent Image"
    }
  },
  "6": {
    "inputs": {
      "text": "{{prompt}}",
      "clip": [
        "4",
        1
      ]
    },
    "class_type": "CLIPTextEncode",
    "_meta": {
      "title": "CLIP Text Encode (Prompt)"
    }
  },
  "7": {
    "inputs": {
      "text": "text, watermark",
      "clip": [
        "4",
        1
      ]
    },
    "class_type": "CLIPTextEncode",
    "_meta": {
      "title": "CLIP Text Encode (Prompt)"
    }
  },
  "8": {
    "inputs": {
      "samples": [
        "3",
        0
      ],
      "vae": [
        "4",
        2
      ]
    },
    "class_type": "VAEDecode",
    "_meta": {
      "title": "VAE Decode"
    }
  },
  "9": {
    "inputs": {
      "filename_prefix": "ComfyUI",
      "images": [
        "8",
        0
      ]
    },
    "class_type": "SaveImage",
    "_meta": {
      "title": "Save Image"
    }
  }
}
",
  "output_quality": {{output_quality}},
  "randomise_seeds": {{randomise_seeds}},
  "force_reset_cache": {{force_reset_cache}},
  "return_temp_files": {{return_temp_files}}
}
